#!/usr/bin/env bun
// Generate `src/server/embedded-assets.ts` from `dist/client/`.
//
// Reads every file under `dist/client/` (recursively), base64-encodes it,
// and emits a single module that exports `EMBEDDED_FILES` — a populated
// `Map<string, Uint8Array>` keyed by absolute URL path. The release
// pipeline runs this step between `vite build` and `bun build --compile`
// so the compiled binary carries the SPA inside itself.
//
// Locally, `bun run build:embed` reproduces the same overwrite.
// IMPORTANT: don't commit the regenerated file — the main branch keeps
// the empty stub. After local verification, restore it with
// `git checkout src/server/embedded-assets.ts`.

import { readFileSync, readdirSync, statSync, writeFileSync } from "node:fs";
import { join, relative, resolve, sep } from "node:path";

const REPO_ROOT = resolve(import.meta.dir, "..");
const DIST = join(REPO_ROOT, "dist", "client");
const OUT = join(REPO_ROOT, "src", "server", "embedded-assets.ts");

const walk = (dir: string, acc: string[] = []): string[] => {
  for (const name of readdirSync(dir)) {
    const abs = join(dir, name);
    if (statSync(abs).isDirectory()) walk(abs, acc);
    else acc.push(abs);
  }
  return acc;
};

let files: string[];
try {
  files = walk(DIST).sort();
} catch (cause) {
  console.error(`generate-embedded-assets: cannot read ${DIST}`);
  console.error(cause instanceof Error ? cause.message : String(cause));
  console.error("Did you run 'bun run build' first?");
  process.exit(1);
}

if (files.length === 0) {
  console.error(`generate-embedded-assets: no files found under ${DIST}`);
  console.error("Did you run 'bun run build' first?");
  process.exit(1);
}

const entries: string[] = [];
let totalBytes = 0;
for (const abs of files) {
  const rel = relative(DIST, abs).split(sep).join("/");
  const urlPath = `/${rel}`;
  const bytes = readFileSync(abs);
  totalBytes += bytes.byteLength;
  const b64 = bytes.toString("base64");
  entries.push(`  [${JSON.stringify(urlPath)}, d(${JSON.stringify(b64)})],`);
}

const module = `// AUTOGENERATED by bin/generate-embedded-assets.ts. Do not edit by hand.
//
// SPA bytes baked into the compiled binary, keyed by the absolute URL
// path a browser would request. The main-branch source has an empty
// Map; this file is overwritten by the release pipeline before
// 'bun build --compile' so the binary carries the SPA inside itself.

const d = (b64: string): Uint8Array =>
  Uint8Array.from(atob(b64), (c) => c.charCodeAt(0));

export const EMBEDDED_FILES: Map<string, Uint8Array> = new Map([
${entries.join("\n")}
]);
`;

writeFileSync(OUT, module);
const kb = (totalBytes / 1024).toFixed(1);
console.log(`generated ${relative(REPO_ROOT, OUT)} — ${files.length} files, ${kb} KB raw`);
